INSERT INTO "feature_requests" ("id","employee_id","title","description","category","priority","status","admin_comment","created_at","updated_at") VALUES(3,26,'ログイン画面が左に寄ってる',replace('社内システムなので直す必要はないですが、ログイン画面が左に寄ってます。\n社外向けに作るときは、表示位置の考慮必要かもです。\n後、ブラウザ利用するシステムの場合は、使用するブラウザ（chrome、Edgeなど）での表示テストも必要かもです。\n\n\n\n','\n',char(10)),'other','low','completed',replace('ご確認ありがとうございます。\n・ログイン画面を中央に修正しました。\n・対応ブラウザについては、マニュアルに記載するようにいたしました。\n\n※なお、現時点での確認済みブラウザは以下のものとなっています。\n-Google Chrome（推奨）\n-Microsoft Edge（Chromium版）\n-Firefox\n\nよろしくお願いいたします。','\n',char(10)),'2026-01-14 10:54:19','2026-01-16 08:36:13');
INSERT INTO "feature_requests" ("id","employee_id","title","description","category","priority","status","admin_comment","created_at","updated_at") VALUES(4,23,'申請済みの当月残業合計時間が知りたい',replace('・月次（当月、前月くらいまで？）の合計残業実績がポータル内で確認できると、より便利でありがたいです！\n・日次で残業申請をバラバラと上げていますが、月次でも業務量を把握したいためです！','\n',char(10)),'improvement','low','completed',replace('ダッシュボードに月間の残業時間を確認できる枠を設置しました。\n申請済み、承認済み、承認待ちごとの時間数がわかるようにしています。\nよろしくお願いいたします。','\n',char(10)),'2026-01-30 01:09:08','2026-02-02 07:52:13');
INSERT INTO "feature_requests" ("id","employee_id","title","description","category","priority","status","admin_comment","created_at","updated_at") VALUES(5,8,'申請を複数選択して一括承認できるようにしたいです',replace('現状申請の承認を行う際に１件ずつボタンを押していく必要があります。\n件数があるので選択して一気に承認できるようにしたいです。','\n',char(10)),'new_feature','high','completed',replace('申請承認を一括して操作できる機能を実装しました。\n\n「申請一覧」ページ\n→複数の承認待ち申請を選択（チェックボックス）\n→枠右上の「選択した申請を一括承認 (N)」ボタンをクリック\n→確認ダイアログで「OK」で一括承認できます。','\n',char(10)),'2026-02-02 05:13:19','2026-02-02 08:59:37');
